        expect(errors.length).toBeGreaterThan(0);
        expect(count).toBe(0);
        done();
      } catch (err) {
        done(err);
      }
    });

    process.nextTick(() => {
      mockReadStream.emit('data', '{"key":"x","val":1}\n');
      mockReadStream.emit('data', ''); // empty chunk triggers the behavioral difference
      mockReadStream.emit('end');
      mockReadStream.emit('close');
    });
  });
});
